import { jsonResponse } from '../utils.js';

export async function onRequestGet(context) {
  const { env } = context;

  const resendApiKey = env.RESEND_API_KEY;
  if (!resendApiKey) {
    return jsonResponse({ error: 'RESEND_API_KEY no configurada' }, 500);
  }

  const testEmail = 'valentinfernandez2006@gmail.com';
  const fromEmail = env.RESEND_FROM_EMAIL || 'Agustina Reynoso <noreply@agusreyncakes.com>';

  const htmlBody = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8" />
  <style>
    body { font-family: Georgia, serif; background: #FAF5EF; margin: 0; padding: 0; }
    .container { max-width: 600px; margin: 0 auto; background: #fff; padding: 40px; }
    .header { text-align: center; margin-bottom: 32px; }
    .brand { font-family: Georgia, serif; font-style: italic; font-size: 32px; color: #3D2E2A; }
    .brand span { color: #C97B7B; }
    h1 { font-family: Georgia, serif; font-weight: 300; font-size: 28px; color: #3D2E2A; margin: 0 0 8px; }
    p { color: #6B5953; line-height: 1.6; }
    .footer { text-align: center; margin-top: 32px; color: #9A8880; font-size: 12px; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <div class="brand">agustina<span>.</span></div>
    </div>
    <h1>¡Test de email! ✿</h1>
    <p>Hola Valentin,</p>
    <p>Este es un email de prueba para verificar que Resend está configurado correctamente.</p>
    <p>Si recibiste este email, ¡todo está funcionando! 🎉</p>
    <div class="footer">
      agustina reynoso · recetas de autora<br/>
      Hecho con harina & amor en Justiniano Posse
    </div>
  </div>
</body>
</html>
  `.trim();

  const payload = {
    from: fromEmail,
    to: [testEmail],
    subject: `Test de configuración ✿ agustina reynoso`,
    html: htmlBody
  };

  const emailRes = await fetch('https://api.resend.com/emails', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${resendApiKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(payload)
  });

  const emailResult = await emailRes.json().catch(() => ({}));

  if (!emailRes.ok) {
    console.error('[TEST-EMAIL] Resend error:', emailResult);
    return jsonResponse({ error: emailResult.message || 'Error al enviar email', details: emailResult }, 400);
  }

  return jsonResponse({ 
    success: true, 
    messageId: emailResult.id,
    to: testEmail,
    message: 'Email de prueba enviado. Revisa tu bandeja de entrada (o spam).'
  });
}
